import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function customTokenAuth(
  request: ZuploRequest,
  context: ZuploContext,
): Promise<ZuploRequest | Response> {
  const authorization = request.headers.get("authorization");
  if (!authorization) {
    return unauthorizedResponse();
  }

  const [scheme, token] = authorization.split(" ");
  if (scheme !== "CustomToken" || !token) {
    return unauthorizedResponse();
  }

  const runId = context.env.ZEALT_RUN_ID;
  const expectedToken = `secret-token-${runId}`;
  if (token !== expectedToken) {
    return unauthorizedResponse();
  }

  return request;
}

function unauthorizedResponse(): Response {
  return new Response(JSON.stringify({ error: "Unauthorized" }), {
    status: 401,
    headers: {
      "content-type": "application/json",
    },
  });
}

export default async function protectedHandler(): Promise<Response> {
  return new Response("Hello, authenticated user!", {
    status: 200,
    headers: {
      "content-type": "text/plain",
    },
  });
}

